const rows = items
  .map(item => item.json)
  .filter(r => (r.status || '').toLowerCase() === 'pending' && String(r.jobRef || '').trim() !== '')
  .sort((a, b) => {
    const aTime = Date.parse(a.receivedAt || '') || 0;
    const bTime = Date.parse(b.receivedAt || '') || 0;
    return aTime - bTime;
  });

return rows.length ? [{ json: rows[0] }] : [];

const lead = $item(0).$node['Take first match1'].json;
const scrape = $json || {};
const user = $item(0).$node['Find matching user1'].json || {};
const queue = $item(0).$node['Take oldest pending1'].json || {};
return [{
  json: {
    ...lead,
    queue_id: queue.queue_id || '',
    queueKey: queue.queueKey || '',
    jobRef: queue.jobRef || lead['Job Ref'] || '',
    userKey: queue.userKey || user.userKey || '',
    Description: scrape.description || lead.Description || '',
    scrapedUrl: scrape.url || lead['Job URL'] || '',
    outputChatId: user.outputChatId || '',
    customPrompt: user.customPrompt || '',
    userName: user.name || ''
  }
}];

function decodeHtmlEntities(s) {
  return String(s)
    .replace(/&amp;/g, "&")
    .replace(/&lt;/g, "<")
    .replace(/&gt;/g, ">")
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'");
}

function cleanForEmail(v) {
  if (v === null || v === undefined) return "";
  let s = String(v);

  s = s.replace(/\\\\r\\\\n/g, "\n")
       .replace(/\\\\n/g, "\n")
       .replace(/\\\\r/g, "\n")
       .replace(/\\r\\n/g, "\n")
       .replace(/\\n/g, "\n")
       .replace(/\\r/g, "\n");

  s = s.replace(/\r\n/g, "\n")
       .replace(/\r/g, "\n")
       .replace(/[ \t]+\n/g, "\n")
       .replace(/\n{3,}/g, "\n\n")
       .trim();

  return decodeHtmlEntities(s);
}

function pick(obj, keys) {
  for (const k of keys) {
    const v = obj && obj[k];
    if (v !== undefined && v !== null && String(v).trim() !== "") return v;
  }
  return "";
}

return items.map(item => {
  const json = item.json || {};

  const sourceMeta = $item(0).$node["Code in JavaScript1"].json || {};

  let aiRoot = json;
  if (
    json.output &&
    typeof json.output === "object" &&
    !Array.isArray(json.output)
  ) {
    aiRoot = json.output;
  }

  let ai = aiRoot.output || {};
  if (typeof ai === "string") {
    try {
      ai = JSON.parse(ai);
    } catch (e) {
      ai = {};
    }
  }

  return {
    json: {
      "Company": cleanForEmail(sourceMeta.company || ""),
      "Job title": cleanForEmail(sourceMeta.title || ""),
      "Location": cleanForEmail(sourceMeta.location || ""),
      "Date posted": cleanForEmail(sourceMeta.datePosted || ""),

      "Candidate Search Boolean": cleanForEmail(pick(ai, ["Candidate Search Boolean"])),
      "Hiring Manager Search Boolean": cleanForEmail(pick(ai, ["Hiring Manager Search Boolean"])),
      "Hiring Manager Name": cleanForEmail(pick(ai, ["Hiring Manager Name"])),

      "Outreach 1": cleanForEmail(pick(ai, ["Outreach 1"])),
      "Outreach 2": cleanForEmail(pick(ai, ["Outreach 2"])),
      "Outreach 3": cleanForEmail(pick(ai, ["Outreach 3"])),
      "Outreach 4": cleanForEmail(pick(ai, ["Outreach 4"])),
      "Outreach 5": cleanForEmail(pick(ai, ["Outreach 5"])),

      "outputChatId": $item(0).$node["Code in JavaScript1"].json.outputChatId || "",
      "userName": $item(0).$node["Code in JavaScript1"].json.userName || ""
    }
  };
});

return items.map(item => {
  const d = item.json;

  const safe = (value) => {
    if (value === undefined || value === null || value === '') return 'Not provided';
    return String(value)
      .replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;');
  };

  const formatLongDate = (date) => {
    const days = ['Sunday', 'Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday'];
    const months = ['January', 'February', 'March', 'April', 'May', 'June', 'July', 'August', 'September', 'October', 'November', 'December'];

    const dayName = days[date.getDay()];
    const day = date.getDate();
    const month = months[date.getMonth()];
    const year = date.getFullYear();

    const getOrdinal = (n) => {
      if (n >= 11 && n <= 13) return `${n}th`;
      const lastDigit = n % 10;
      if (lastDigit === 1) return `${n}st`;
      if (lastDigit === 2) return `${n}nd`;
      if (lastDigit === 3) return `${n}rd`;
      return `${n}th`;
    };

    return `${dayName} ${getOrdinal(day)} ${month} ${year}`;
  };

  const now = new Date();
  const createdDate = formatLongDate(now);

  const spacer = '<p>&nbsp;</p>';
  const divider = '<hr style="border:0;border-top:1px solid #cccccc;margin:16px 0;">';

  item.json.teamsMessage = `
<h2 style="font-size:28px; line-height:1.2;">New Five Step Campaign - ${safe(createdDate)}</h2>
${divider}

<h3>Company Details</h3>
<p><strong>Company:</strong> ${safe(d["Company"])}</p>
<p><strong>Job title:</strong> ${safe(d["Job title"])}</p>
<p><strong>Location:</strong> ${safe(d["Location"])}</p>
<p><strong>Date Posted:</strong> ${safe(d["Date posted"])}</p>
${divider}

<h3>Hiring Manager</h3>
<p><strong>Hiring Manager Name:</strong><br>${safe(d["Hiring Manager Name"])}</p>
${divider}

<h3>Outreach 1</h3>
<p>${safe(d["Outreach 1"]).replace(/\n/g, '<br>')}</p>
${divider}

<h3>Outreach 2</h3>
<p>${safe(d["Outreach 2"]).replace(/\n/g, '<br>')}</p>
${divider}

<h3>Outreach 3</h3>
<p>${safe(d["Outreach 3"]).replace(/\n/g, '<br>')}</p>
${divider}

<h3>Outreach 4</h3>
<p>${safe(d["Outreach 4"]).replace(/\n/g, '<br>')}</p>
${divider}

<h3>Outreach 5</h3>
<p>${safe(d["Outreach 5"]).replace(/\n/g, '<br>')}</p>
${spacer}

<p>Best,<br>${safe(d.userName || 'Antony')}</p>
`.trim();

  item.json.outputChatId = d.outputChatId || '';
  item.json.userName = d.userName || '';
  return item;
});

const userKey = String(
  $item(0).$node['Take oldest pending1'].json['userKey'] || ''
).trim();

const users = items.map(i => i.json);
const match = users.find(u => {
  const k = String(u.userKey || u['userKey '] || u['UserKey'] || '').trim();
  return k === userKey;
});

if (match) {
  return [{ json: match }];
}
return [{ json: { userKey, outputChatId: '', customPrompt: '', name: '' } }];
